using System;class A{static void Main(){var p=Console.ReadLine().Split(' ');int w=int.Parse(p[0]),h=int.Parse(p[1]);Console.ReadLine();p=Console.ReadLine().Split(' ');int x=int.Parse(p[0]),y=int.Parse(p[1]),a=0,b=0,c=w-1,d=h-1;for(;;){var s=Console.ReadLine();if(s.Contains("U"))d=y-1;if(s.Contains("D"))b=y+1;if(s.Contains("L"))c=x-1;if(s.Contains("R"))a=x+1;x=(a+c)/2;y=(b+d)/2;Console.WriteLine(x+" "+y);}}}